<?php  namespace App\Http\Controllers\Admin;  use App\Http\Controllers\Controller; use App\Models\BlogPost; use App\Models\Lead; use App\Models\Service; use Illuminate\Support\Facades\DB;  class DashboardController extends Controller {     public function index()     {         $stats = [             "new_leads"          => Lead::where("status", "new")->count(),             "today_leads"        => Lead::whereDate("created_at", now()->toDateString())->count(),             "draft_posts"        => BlogPost::where("is_published", false)->count(),             "published_services" => Service::where("is_published", true)->count(),             "active_jobs"        => \App\Models\Job::where("is_active", true)->count(),         ];          $leadsByType = Lead::select("type", DB::raw("count(*) as total"))             ->groupBy("type")             ->pluck("total", "type")             ->toArray();          $recentLeads = Lead::latest()->take(10)->get();          return view("admin.dashboard.index", compact("stats", "leadsByType", "recentLeads"));     } }